svg.script:
const svg = document.documentElement;

const ball = document.getElementById("ball");
const left = document.getElementById("leftPaddle");
const right = document.getElementById("rightPaddle");

const W = 600;
const H = 400;

let bx = 300, by = 200;
let vx = 3.5, vy = 2.2;
const r = 8;

let lpY = 150;
let rpY = 150;
const paddleH = 100;

function reset() {
  bx = 300;
  by = 200;
  vx = (Math.random() > 0.5 ? 1 : -1) * 3.5;
  vy = (Math.random() * 2 - 1) * 2.5;
}

function update() {
  // Move paddles (simple AI tracking with lag)
  lpY += ((by - paddleH/2) - lpY) * 0.08;
  rpY += ((by - paddleH/2) - rpY) * 0.08;

  lpY = Math.max(0, Math.min(H - paddleH, lpY));
  rpY = Math.max(0, Math.min(H - paddleH, rpY));

  left.setAttribute("y", lpY);
  right.setAttribute("y", rpY);

  // Move ball
  bx += vx;
  by += vy;

  // Top/bottom collision
  if (by - r < 0 || by + r > H) {
    vy *= -1;
  }

  // Left paddle collision
  if (
    bx - r < 30 &&
    by > lpY &&
    by < lpY + paddleH &&
    vx < 0
  ) {
    vx *= -1;

    // add angle based on hit position
    let offset = (by - (lpY + paddleH/2)) / (paddleH/2);
    vy += offset * 2;
  }

  // Right paddle collision
  if (
    bx + r > 570 &&
    by > rpY &&
    by < rpY + paddleH &&
    vx > 0
  ) {
    vx *= -1;

    let offset = (by - (rpY + paddleH/2)) / (paddleH/2);
    vy += offset * 2;
  }

  // Score/reset if missed
  if (bx < 0 || bx > W) {
    reset();
  }

  ball.setAttribute("cx", bx);
  ball.setAttribute("cy", by);

  requestAnimationFrame(update);
}

update();
